#include<bits/stdc++.h>
using namespace std;
const int MAXN=1e5+5;
long long place[MAXN],pre[MAXN],money[MAXN],pre2[MAXN];
int main()
{
	int n,m;
	cin>>n>>m;
	for(int i=1;i<=m;i++){
		cin>>place[i];
		if(i!=1){
			int mini=min(place[i],place[i-1]);
			int maxi=max(place[i],place[i-1]);
			pre[mini]++;
			pre[maxi]--;
		}
	}
	for(int i=1;i<=n;i++){
		pre2[i]=pre2[i-1]+pre[i];
	//	cout<<pre2[i]<<" ";
	}
	long long ans=0;
	for(int i=1;i<n;i++){
		int a,b,c;
		cin>>a>>b>>c;
		if((pre2[i]*a)>(c+b*pre2[i])){
			money[i]=c+b*pre2[i];
		}else{
			money[i]=a*pre2[i];
		//	cout<<i<<endl;
		}
		ans+=money[i];
//		cout<<endl<<money[i]<<endl;
	}
	cout<<ans;

}
